from sentence_transformers import SentenceTransformer, util

class TimePartitionNode:
    def __init__(self, label, timestamp):
        self.label = label  # e.g., 'Day', 'Week'
        self.timestamp = timestamp  # Timestamp for this node
        self.data = []  # Holds data entries for this partition
        self.children = defaultdict(TimePartitionNode)  # Sub-partitions
        self.embedding_store = []  # Holds embeddings for semantic queries

    def add_data(self, entry, metadata, model=None):
        self.data.append({"entry": entry, "metadata": metadata})
        if model:
            embedding = model.encode(entry, convert_to_tensor=True)
            self.embedding_store.append((embedding, {"entry": entry, "metadata": metadata}))

    def semantic_query(self, query, model, top_k=5):
        query_embedding = model.encode(query, convert_to_tensor=True)
        similarities = [(util.pytorch_cos_sim(query_embedding, embedding), data) 
                        for embedding, data in self.embedding_store]
        similarities = sorted(similarities, key=lambda x: x[0], reverse=True)
        return [data for _, data in similarities[:top_k]]

    def get_data(self):
        return self.data

    def __repr__(self):
        return f"Partition(label={self.label}, timestamp={self.timestamp}, data_count={len(self.data)})"

